var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_OWL","text":{"KOREA":"<color=#ffd34c>이쪽은 거의 한계입니다! 놈들의 화기가 저희 방벽을 관통하고 있어요!</color>","JPN":"<color=#ffd34c>こちらはもう限界っす！　奴らの火器が俺たちの防壁を貫通してるっす！</color>","ENG":"<color=#ffd34c>We're at our limit here! Their firepower is starting to penetrate our walls!</color>","TWN":"<color=#ffd34c>這裡快撐不住了！那些傢伙的武器正在突破我們的屏障！</color>"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L3_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_MONKEY","text":{"KOREA":"<color=#ffd34c>놈들이 운용하는 모든 기계가 지뢰에 대비되어 있소. 순수 전력만으론 우리도 오래 버티기 힘들 거요.</color>","JPN":"<color=#ffd34c>奴らが使っている機械すべてに地雷対策がしてある。戦力だけでは俺たちも長くは持たないだろう。</color>","ENG":"<color=#ffd34c>All their machines were mine-ready. Just looking at power alone, we will not be able to hold out much longer.</color>","TWN":"<color=#ffd34c>那些傢伙使用的所有機械都能對抗地雷，單憑我們的戰力是撐不久的。</color>"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"연합원들이 흘린 피가…… 결계옥에 스며들고 있어.","JPN":"連合員から流れた血が……結界玉に取り込まれている。","ENG":"The blood split by our members... It is being absorbed by Akaitama.","TWN":"聯盟成員流的血……正滲入結界玉石。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"잠든 명부신의 영혼을 깨운 듯하군요. 저승의 기운과…… 가문 사람들의 피로……","JPN":"眠りし冥府の神の魂を目覚めさせたようですね。冥府の気と……家門の者たちの血で……","ENG":"It appears they have awoken the soul of the Nether God. With the aura of the Afterlife... and with the blood of our families...","TWN":"他們似乎是想利用地獄的氣息……和族人的血，來喚醒沉睡的冥府神靈魂……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"신의 의식이 각성을 마치고, 이제 곧 재구축될 것이오.","JPN":"神の意識が覚醒し、もうすぐ再構築される。","ENG":"Soon as the god's consciousness is awakened, he will be reborn.","TWN":"神的意識已經甦醒，很快就會重新組織起來。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그렇게 되면 인간이 두려워할 것은 더 이상 침식체 따위가 아니게 되겠지.","JPN":"そうなれば、人間が恐れるものは侵食体なんかではなくなるだろう。","ENG":"No longer will man be afraid of C.O.s.","TWN":"如此一來，人類該畏懼的將不再是侵蝕體這種小角色。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"무모합니다. 당신들이 감히 신을 통제할 수 있을 거라고 생각하나요?","JPN":"無謀です。あなたたちに神が操れると思いますか？","ENG":"This is reckless. Do you really think you can control of god?","TWN":"荒謬，你們竟然認為自己可以控制神？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"들었거든.","JPN":"聞いたのだ。","ENG":"I have already heard.","TWN":"我有聽到，"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"우리가 신을 완성시키고, 인간이 그 힘을 거머쥐는 미래를 들었소.","JPN":"我らが神を完成させ、人間がその力を手にする未来を。","ENG":"Future whispers to me that once the rebuilding of god is complete, man will wield his power.","TWN":"我聽到未來說，我們將神完成後，人類會掌握那股力量。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그대들이 섬기는 바람의 목소리가, 그대들이 말하는 운명이, 그렇게 말해주었지.","JPN":"そなたたちが崇める風の声が、そなたたちが言う運命が、そう言ってくれた。","ENG":"This voice of wind you all worship, what you call \\"fate\\"... It has spoken to me.","TWN":"是你們侍奉的風聲，你們所說的命運，這樣告訴我的。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"왜 그러지?","JPN":"どうした？","ENG":"What is it?","TWN":"怎麼了？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그토록 신봉해오던 바람의 목소리가 그대들을 배신하니 충격을 받은 것 같군.","JPN":"そこまで信じていた風の声に裏切られ、ショックを受けたみたいだな。","ENG":"Shocked to hear that the voice of wind you all put your faith in has betrayed you?","TWN":"因為你曾經侍奉的風聲背叛你，受到很大的打擊嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"하지만 이것이 진실이오.","JPN":"だが、これが真実だ。","ENG":"However, this is the truth.","TWN":"但這是真的。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"미래는 정해진 주인 없이, 그저 강자에 의해 지배될 뿐.","JPN":"未来は誰かの物ではなく、ただ強者によって支配されるのみ。","ENG":"The future has no master. It is merely ruled by the strong.","TWN":"未來沒有固定的主人，它只會受到強者的支配。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"당신들이 하려는 짓은 약육강식이 아닙니다. 사람들 모두를 위험에 빠트릴 뿐이죠.","JPN":"あなたたちがやろうとしていることは弱肉強食ではありません。すべての人間を危険に晒すだけです。","ENG":"What you are doing has nothing to do with the survival of the fittest. It only jeopardizes everyone.","TWN":"你們的行為並不是弱肉強食，僅僅是讓所有人陷入危險而已。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런 짓은 용서할 수 없어요. 절대로.","JPN":"それは許しません。絶対に。","ENG":"And that, I can absolutely not forgive you for.","TWN":"我無法原諒你們的行為，無法！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님! 그 힘은 쓰시면 안 됩니다!","JPN":"ご当主様！　その力は使ってはなりません！","ENG":"Lady Nanahara! You must not use that power!","TWN":"堂主！不可以使用那股力量！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"사나에…?","JPN":"早苗……？","ENG":"Sanae...?","TWN":"早苗……？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"큭?","JPN":"くっ！？","ENG":"Kgh?","TWN":"唔？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그렇게 한눈 팔고 있을 때야 아줌마?","JPN":"よそ見している場合、おばさん？","ENG":"Hey, don't you have bigger problems to face right now?","TWN":"現在不是分心的時候吧，大嬸？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"죽을상 짓지 말고 좀 더 발버둥쳐봐.","JPN":"苦しそうな顔ばかりしてないでもっとあがいてよ。","ENG":"Stop making that foul face and suffer more for me.","TWN":"別一副要死不活的樣子，再用力掙扎一下嘛。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아버지께선 너희가 살아있을 때 최대한 많은 피를 흘리길 원하시거든.","JPN":"お父様はお前たちが生きているうちにできるだけ多くの血を流させたいんだから。","ENG":"Father wants you to bleed out while you're still alive!","TWN":"父親希望你們活著時可以盡量多流一點血。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"사나에! 안돼!","JPN":"早苗！　いけません！","ENG":"Sanae! No!","TWN":"早苗！不要！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"으윽……","JPN":"ぬぅう……","ENG":"Urgh...","TWN":"呃呃……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"이걸로 한동안 꼼짝 못하겠네.","JPN":"これでしばらくは動けないわよ。","ENG":"Guess you won't be moving for a while now.","TWN":"這下你應該好一陣子都不能動了吧？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"자아, 그럼 어디부터 잘라줄까? 도망치지 못하게 다리부터?","JPN":"さあ、どこから切ってあげようかしら？　逃げられないように足から？","ENG":"Now then, where should I start slicing first? Should I start with your legs, so you can't run away?","TWN":"來吧，要從哪裡開始砍呢？先砍腿，免得你逃跑？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……퉤.","JPN":"……ぺっ。","ENG":"...Ptui!","TWN":"……呸。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"잘 알겠어. 일단 그 혀부터 잘라서 피를……","JPN":"よくわかったわ。まずその舌から切って血を……","ENG":"All right. I'll just cut your tongue first and make you ble–","TWN":"很好，那就先砍掉你的舌頭……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"뭐야……? 화살?","JPN":"なに……？　矢？","ENG":"Huh...? An arrow?","TWN":"什麼……？是箭？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};